INSERT INTO `heritage_project` (`id`,`name`,`category_id`,`level`,`description`,`region`,`image_url`,`status`,`created_at`,`updated_at`) VALUES
(1,'南通蓝印花布印染技艺',13,'国家级','蓝印花布是中国传统的手工印花染色技术，以蓝白两色为主色调，图案朴素优美，具有浓郁的民间艺术风格。南通蓝印花布印染技艺历史悠久，源于宋代，兴盛于明清，是中国民间印染技艺的典型代表。其制作过程包括设计图稿、镂刻花版、调制浆料、刮浆上布、入缸浸染、刮白整理等多道工序。','江苏南通','https://picsum.photos/seed/heritage01/800/600',1,'2025-01-02 00:00:00','2025-01-02 00:00:00'),
(2,'景德镇手工制瓷技艺',10,'国家级','景德镇传统手工制瓷技艺涵盖了拉坯、利坯、画坯、施釉和烧窑等72道工序，是中华陶瓷文化的瑰宝。景德镇自五代时期便开始制瓷，历经宋、元、明、清千年传承，形成了独特的制瓷体系，被誉为"瓷都"。','江西景德镇','https://picsum.photos/seed/heritage02/800/600',1,'2025-01-02 00:00:00','2025-01-02 00:00:00'),
(3,'苏州刺绣',9,'国家级','苏绣是中国四大名绣之一，以精细雅洁著称，题材广泛，技法独特，色彩清雅。苏绣发源于江苏苏州，迄今已有两千多年的历史。以精细、素雅、均匀著称，其特点是图案秀丽、构思巧妙、针法活泼、色彩清雅。','江苏苏州','https://picsum.photos/seed/heritage03/800/600',1,'2025-01-02 00:00:00','2025-01-02 00:00:00'),
(4,'东阳木雕',11,'国家级','东阳木雕因产于浙江东阳而得名，以平面浮雕为主，题材多为花鸟山水、民间故事。东阳木雕约始于唐代，至今已有千余年历史，是中国民间雕刻艺术的典型代表。','浙江东阳','https://picsum.photos/seed/heritage04/800/600',1,'2025-01-02 00:00:00','2025-01-02 00:00:00'),
(5,'福州脱胎漆器髹饰技艺',12,'国家级','福州脱胎漆器与北京景泰蓝、江西景德镇瓷器并誉为中国传统工艺"三宝"。脱胎漆器质地坚固轻巧、造型典雅别致、色泽瑰丽鲜艳、装饰精细巧妙，是中国漆器艺术的巅峰之作。','福建福州','https://picsum.photos/seed/heritage05/800/600',1,'2025-01-02 00:00:00','2025-01-02 00:00:00'),
(6,'中国剪纸',8,'国家级','中国剪纸是世界级非物质文化遗产，用剪刀或刻刀在纸上剪刻花纹，用于装点生活或配合民俗活动。2009年入选联合国教科文组织人类非物质文化遗产代表作名录。','全国','https://picsum.photos/seed/heritage06/800/600',1,'2025-01-02 00:00:00','2025-01-02 00:00:00'),
(7,'豫剧',5,'国家级','豫剧是中国五大戏曲剧种之一，起源于河南，以唱腔铿锵大气、抑扬有度著称。豫剧原称河南梆子，又名河南高调、靠山吼，是中原地区最具代表性的戏曲形式。','河南','https://picsum.photos/seed/heritage07/800/600',1,'2025-01-03 00:00:00','2025-01-03 00:00:00'),
(8,'竹编工艺',14,'省级','利用竹子的韧性和弹性，通过编、织、穿、绕等手法制作各种生活用品和工艺品。四川竹编历史悠久，技艺精湛，产品种类繁多，是中国传统手工编织艺术的杰出代表。','四川','https://picsum.photos/seed/heritage08/800/600',1,'2025-01-03 00:00:00','2025-01-03 00:00:00'),
(9,'汝瓷烧制技艺',10,'省级','汝瓷以温润的天青色闻名于世，烧制工艺复杂，需精确控制窑温和还原气氛。汝窑位列宋代五大名窑之首，有"汝窑为魁"之赞誉，其釉色"雨过天青云破处"为历代文人所推崇。','河南汝州','https://picsum.photos/seed/heritage09/800/600',1,'2025-01-04 00:00:00','2025-01-04 00:00:00'),
(10,'朱仙镇木版年画',16,'国家级','朱仙镇木版年画起源于北宋，是中国四大年画之一，以线条粗犷、色彩鲜艳著称。年画题材多取自历史故事、神话传说和民间生活，寄托了劳动人民的美好愿望。','河南开封','https://picsum.photos/seed/heritage10/800/600',1,'2025-01-04 00:00:00','2025-01-04 00:00:00'),
(11,'蜀绣',9,'国家级','蜀绣又名川绣，与苏绣、湘绣、粤绣齐名为中国四大名绣。蜀绣以针法精细、色彩明丽闻名，尤以"车拧针"独具特色，所绣花鸟走兽逼真生动。','四川成都','https://picsum.photos/seed/heritage11/800/600',1,'2025-01-05 00:00:00','2025-01-05 00:00:00'),
(12,'大理白族扎染技艺',13,'省级','大理白族扎染技艺是云南传统手工印染技术，以板蓝根为染料，图案独具民族特色。周城被誉为"扎染之乡"，扎染产品以蓝白两色为主，清新素雅。','云南大理','https://picsum.photos/seed/heritage12/800/600',1,'2025-01-05 00:00:00','2025-01-05 00:00:00'),
(13,'宜兴紫砂陶制作技艺',10,'国家级','宜兴紫砂壶以其独特的材质和精湛的工艺闻名世界，集造型、绘画、诗文、书法、篆刻于一体，具有极高的艺术价值和收藏价值。紫砂矿料经过多道工序加工成型后烧制而成。','江苏宜兴','https://picsum.photos/seed/heritage13/800/600',1,'2025-01-06 00:00:00','2025-01-06 00:00:00'),
(14,'湘绣',9,'国家级','湘绣是中国四大名绣之一，以湖南长沙为中心，至今已有两千多年历史。以丝绒线绣花，技术精湛，风格多变，尤以狮虎走兽绣品最为出名，被誉为"绣花可以闻香"。','湖南长沙','https://picsum.photos/seed/heritage14/800/600',1,'2025-01-06 00:00:00','2025-01-06 00:00:00'),
(15,'唐三彩烧制技艺',10,'省级','唐三彩是中国古代陶瓷烧制工艺的珍品，以黄、绿、白三色为主要釉色，造型生动，釉色斑斓，是唐代文化繁荣的实物见证。洛阳唐三彩烧制技艺传承千年。','河南洛阳','https://picsum.photos/seed/heritage15/800/600',1,'2025-01-07 00:00:00','2025-01-07 00:00:00'),
(16,'苗族银饰锻制技艺',2,'国家级','苗族银饰锻制技艺流传于贵州、湖南等苗族聚居区，以其造型独特、工艺精细著称。银匠手工打造各种头饰、颈饰、胸饰等，是苗族文化的重要载体。','贵州黔东南','https://picsum.photos/seed/heritage16/800/600',1,'2025-01-07 00:00:00','2025-01-07 00:00:00'),
(17,'龙泉青瓷烧制技艺',10,'国家级','龙泉青瓷始于三国两晋，盛于南宋，以"如玉似冰"的釉色闻名天下。2009年入选联合国教科文组织人类非物质文化遗产代表作名录，是全球唯一入选的陶瓷类项目。','浙江龙泉','https://picsum.photos/seed/heritage17/800/600',1,'2025-01-08 00:00:00','2025-01-08 00:00:00'),
(18,'潍坊风筝制作技艺',1,'国家级','潍坊是世界风筝之都，风筝制作历史可追溯到两千多年前。潍坊风筝以其选材讲究、造型优美、扎糊精巧、形象逼真而享誉海内外。','山东潍坊','https://picsum.photos/seed/heritage18/800/600',1,'2025-01-08 00:00:00','2025-01-08 00:00:00');
INSERT INTO `master_profile` (`id`,`user_id`,`title`,`heritage_project_id`,`skill_category_id`,`career_years`,`career_history`,`specialties`,`representative_works`,`bio`,`honor`,`audit_status`,`created_at`,`updated_at`) VALUES
(1,2,'省级非遗传承人',1,13,35,'1990年随祖母学习蓝印花布印染技艺，1995年独立完成第一件作品。2000年被认定为市级非遗传承人，2005年创办"蓝韵坊"工作室。2010年获省级非遗传承人称号。2015年赴日本、法国进行文化交流。2020年受聘为南通大学客座教授，致力于蓝印花布技艺的高校传承。','蓝印花布印染、图案设计、染料配制、传统纹样研究','["蓝印花布百福图","四季花卉蓝印长卷","龙凤呈祥蓝印挂毯","蓝染二十四节气系列"]','张明远，男，1975年生于江苏南通，师承祖母学习蓝印花布印染技艺，从艺35年。致力于传统蓝印花布技艺的传承与创新，在保持传统工艺精髓的基础上融入现代设计元素。曾为G20峰会定制国礼蓝印花布作品。','省级非遗代表性传承人、全国工艺美术优秀创作奖、江苏省民间文艺最高奖"山花奖"',1,'2025-01-05 09:30:00','2025-01-05 09:30:00'),
(2,3,'市级非遗传承人',3,9,28,'1997年进入苏州刺绣研究所学习，师从著名刺绣大师顾文霞。2005年成立个人刺绣工作室"锦绣阁"。2012年被评为市级非遗传承人。2018年作品《千里江山图》被中国国家博物馆收藏。多次受邀参加国内外艺术展览。','苏绣、双面绣、乱针绣、工笔花鸟绣','["百鸟朝凤双面绣屏风","牡丹图团扇","千里江山图长卷刺绣","荷塘月色双面绣"]','李秀芳，女，1980年生于江苏苏州，自幼跟随母亲学习刺绣，后入苏州刺绣研究所深造。从艺28年，擅长双面绣和乱针绣技法，作品融合传统与现代审美。','市级非遗代表性传承人、江苏省工艺美术名人、苏州市十佳民间艺人',1,'2025-01-08 10:00:00','2025-01-08 10:00:00'),
(3,4,'省级非遗传承人',2,10,40,'1985年进入景德镇陶瓷厂学徒，师从高级工艺美术师王锡良。1993年创办"德厚窑"陶瓷工作室。2000年获中国陶瓷艺术大师称号。2008年被授予省级非遗传承人称号。2015年作品入选米兰世博会中国馆展览。','青花瓷、粉彩瓷、拉坯成型、高温颜色釉','["青花山水大瓶","粉彩花鸟茶具套装","仿古青花瓷盘","窑变釉观音瓶"]','王德厚，男，1970年生于江西景德镇，陶瓷世家第四代传人。从艺40年，精通景德镇传统72道制瓷工序，尤擅青花绘制与粉彩技法。作品被多家博物馆收藏。','省级非遗代表性传承人、中国陶瓷艺术大师、景德镇市突出贡献人才',1,'2025-01-12 14:00:00','2025-01-12 14:00:00');
INSERT INTO `master_apprentice_relation` (`id`,`master_id`,`apprentice_id`,`heritage_project_id`,`apply_reason`,`status`,`apply_time`,`approve_time`,`created_at`,`updated_at`) VALUES
(1,2,5,1,'从小对蓝印花布印染技艺有浓厚兴趣，在大学期间选修了相关课程并写了毕业论文，希望跟随张师傅系统学习传统印染工艺。',1,'2025-02-01 10:00:00','2025-02-03 15:00:00','2025-02-01 10:00:00','2025-02-03 15:00:00'),
(2,2,6,1,'大学期间学习过染织设计专业，对传统蓝印花布工艺深感敬佩，希望在张师傅指导下深入学习传统技艺。',1,'2025-02-05 09:00:00','2025-02-07 11:00:00','2025-02-05 09:00:00','2025-02-07 11:00:00'),
(3,3,7,3,'自幼喜爱刺绣，跟随外婆学过基础针法。希望跟随李师傅学习苏绣精湛技法，将这门传统艺术发扬光大。',1,'2025-02-10 14:00:00','2025-02-12 10:00:00','2025-02-10 14:00:00','2025-02-12 10:00:00'),
(4,3,8,3,'美术专业毕业，对刺绣艺术有独特的理解和追求，曾在市级刺绣比赛获得银奖，希望能在李师傅门下深造。',1,'2025-02-15 11:00:00','2025-02-17 09:00:00','2025-02-15 11:00:00','2025-02-17 09:00:00'),
(5,4,9,2,'景德镇陶瓷大学在读研究生，研究方向为传统青花瓷工艺，渴望在王师傅指导下进行实践。',1,'2025-02-20 10:00:00','2025-02-22 14:00:00','2025-02-20 10:00:00','2025-02-22 14:00:00'),
(6,4,10,2,'来自陶瓷之乡，从小耳濡目染，父亲也是制瓷手艺人，希望跟随王师傅系统学习制瓷全工序。',1,'2025-02-25 09:30:00','2025-02-27 16:00:00','2025-02-25 09:30:00','2025-02-27 16:00:00'),
(7,2,11,1,'对非遗文化保护有强烈使命感，新闻传播专业在读，希望通过拜师学习蓝印花布技艺，为非遗纪录片拍摄积累素材。',0,'2025-03-10 08:00:00',NULL,'2025-03-10 08:00:00','2025-03-10 08:00:00'),
(8,3,12,3,'从小对针线活有天赋，在全国大学生手工艺比赛中获得一等奖，立志成为新一代苏绣传承人。',0,'2025-03-12 10:00:00',NULL,'2025-03-12 10:00:00','2025-03-12 10:00:00'),
(9,2,8,1,'曾对蓝印花布产生兴趣但后来选择了刺绣方向。',2,'2025-01-20 09:00:00','2025-01-22 11:00:00','2025-01-20 09:00:00','2025-01-22 11:00:00');
INSERT INTO `teaching_task` (`id`,`title`,`description`,`master_id`,`apprentice_id`,`heritage_project_id`,`skill_category_id`,`deadline`,`status`,`created_at`,`updated_at`) VALUES
(1,'蓝印花布基础图案刻版学习','学习蓝印花布传统图案的刻版技术，包括花卉、动物、几何等常见图案的构图方法和刻版要领。要求每位徒弟完成至少3种不同风格的图案刻版练习。重点掌握刻刀的运用角度和力度控制。',2,NULL,1,13,'2025-04-01 23:59:59',1,'2025-02-10 08:00:00','2025-02-10 08:00:00'),
(2,'传统染料配制与色彩控制','学习使用天然植物靛蓝染料的配制方法，掌握不同浓度下的色彩深浅变化规律。要求记录完整的实验数据，包括温度、浓度、浸泡时间对色彩效果的影响。',2,5,1,13,'2025-04-15 23:59:59',0,'2025-02-20 10:00:00','2025-02-20 10:00:00'),
(3,'苏绣基础针法练习','系统学习平绣、齐针、套针、施针等基础针法，每种针法完成一个10cm*10cm的练习作品，并记录学习心得。要求针脚均匀、线条流畅。',3,NULL,3,9,'2025-03-30 23:59:59',1,'2025-02-15 09:00:00','2025-02-15 09:00:00'),
(4,'双面绣入门技法','在掌握基础针法后，学习双面绣的起针、转针、藏针等核心技法，完成一幅简单的双面绣小品（花卉主题）。要求正反两面图案一致，针脚藏于布中。',3,8,3,9,'2025-05-01 23:59:59',0,'2025-03-01 14:00:00','2025-03-01 14:00:00'),
(5,'拉坯基本功训练','学习景德镇传统拉坯技艺，从揉泥、定中心、开孔、拉筒到成型。每人完成碗、杯、瓶三种基本器型各5件。重点训练手感和泥性理解。',4,NULL,2,10,'2025-04-20 23:59:59',1,'2025-03-01 08:00:00','2025-03-01 08:00:00'),
(6,'青花绘制技法学习','学习传统青花瓷的绘制技法，包括分水、勾线、染色等。要求在素坯上完成一组传统花鸟纹样的绘制。掌握青花料的调配和运笔技巧。',4,10,2,10,'2025-05-15 23:59:59',0,'2025-03-15 10:00:00','2025-03-15 10:00:00'),
(7,'蓝印花布成品制作','综合运用刻版、调浆、刮浆、染色、刮白等完整工序，独立完成一件蓝印花布桌布的制作。这是对前期学习成果的综合检验。',2,6,1,13,'2025-06-01 23:59:59',0,'2025-03-20 09:00:00','2025-03-20 09:00:00'),
(8,'乱针绣创新实践','在传统乱针绣基础上，融入个人创意，以风景或人物为主题，完成一幅不小于30cm*40cm的创新绣品。鼓励大胆尝试色彩搭配和针法创新。',3,7,3,9,'2025-06-15 23:59:59',0,'2025-03-25 11:00:00','2025-03-25 11:00:00'),
(9,'窑炉温度控制实践','学习景德镇传统柴窑烧制的温度控制技术，了解不同温度段对瓷器釉面的影响，记录烧窑全过程数据。掌握还原焰和氧化焰的运用。',4,9,2,10,'2025-06-30 23:59:59',0,'2025-04-01 08:00:00','2025-04-01 08:00:00'),
(10,'非遗文化调研报告','走访当地非遗传承人，收集口述历史资料，撰写一篇不少于3000字的非遗文化调研报告。要求有实地走访照片和录音记录。',2,NULL,1,13,'2025-05-01 23:59:59',0,'2025-03-10 09:00:00','2025-03-10 09:00:00'),
(11,'苏绣配色方案设计','根据苏绣传统配色原理，设计3套不同主题的配色方案（春花/秋叶/山水），每套方案需包含主色、辅色、点缀色的搭配说明。',3,8,3,9,'2025-05-30 23:59:59',0,'2025-04-01 09:00:00','2025-04-01 09:00:00'),
(12,'传统釉料调配实验','学习景德镇传统釉料的组成成分和调配方法，记录不同配比下的釉面效果，完成实验报告。重点研究青白釉和影青釉。',4,10,2,10,'2025-07-15 23:59:59',0,'2025-04-15 10:00:00','2025-04-15 10:00:00');
INSERT INTO `task_submission` (`id`,`task_id`,`apprentice_id`,`content`,`file_url`,`status`,`master_comment`,`score`,`submit_time`,`review_time`,`created_at`,`updated_at`) VALUES
(1,1,5,'完成了牡丹花、蝴蝶和万字纹三种图案的刻版练习。刻版过程中深刻体会到力道控制的重要性，特别是在弧线部分需要一气呵成。','/uploads/submissions/sub_001.jpg',2,'刻版基本功扎实，线条流畅度需要加强。牡丹花的花瓣层次感可以再丰富一些，建议参考明代蓝印花布的经典图样。继续保持学习热情！',85,'2025-03-01 16:00:00','2025-03-03 10:00:00','2025-03-01 16:00:00','2025-03-03 10:00:00'),
(2,1,6,'完成了梅花、喜鹊和回纹三种图案的刻版。梅花的枝干走势比较满意，但喜鹊的羽毛细节处理还需改进，刻刀角度还不够灵活。','/uploads/submissions/sub_002.jpg',2,'构图大气，对传统纹样理解到位。喜鹊的羽毛建议参考宋代花鸟画的处理手法。整体进步明显，期待下一阶段的练习！',88,'2025-03-05 14:30:00','2025-03-07 09:00:00','2025-03-05 14:30:00','2025-03-07 09:00:00'),
(3,3,7,'完成了平绣和齐针两种针法的练习作品。平绣比较顺利，但齐针的针脚均匀度还需加强，手感还在磨合中。','/uploads/submissions/sub_003.jpg',2,'平绣掌握得不错，线条整齐。齐针练习中注意保持每一针的间距一致，建议每天坚持1小时针法练习，形成肌肉记忆。',82,'2025-03-10 15:00:00','2025-03-12 11:00:00','2025-03-10 15:00:00','2025-03-12 11:00:00'),
(4,3,8,'四种基础针法的练习作品全部完成。个人觉得施针最难，容易出现针脚不规则的情况。不过套针的效果比较满意。','/uploads/submissions/sub_004.jpg',2,'进度很快，四种针法全部完成值得表扬！施针确实是难点，建议用细线在薄布上反复练习。你的美术功底对配色很有帮助。',90,'2025-03-08 10:00:00','2025-03-10 14:00:00','2025-03-08 10:00:00','2025-03-10 14:00:00'),
(5,5,9,'完成了5个碗和5个杯的拉坯练习。拉坯时泥料的含水量控制是最大的难点，有几件作品因泥太软而坍塌变形。','/uploads/submissions/sub_005.jpg',2,'拉坯功底不错，器型基本规整。注意揉泥时要把气泡排尽，含水量要根据季节和室温调整。瓶的练习要加快进度。',80,'2025-03-20 16:00:00','2025-03-22 10:00:00','2025-03-20 16:00:00','2025-03-22 10:00:00'),
(6,5,10,'三种器型各完成了5件。碗和杯的成功率较高，瓶的口部处理需要加强，容易出现不圆的情况。附上练习照片记录。','/uploads/submissions/sub_006.jpg',1,NULL,NULL,'2025-03-25 11:00:00',NULL,'2025-03-25 11:00:00','2025-03-25 11:00:00'),
(7,2,5,'记录了不同浓度靛蓝染料的配制过程和上色效果对比。发现温度对染色效果有显著影响，低温出色偏淡，高温出色偏深。附实验数据表。','/uploads/submissions/sub_007.pdf',0,NULL,NULL,'2025-04-01 10:00:00',NULL,'2025-04-01 10:00:00','2025-04-01 10:00:00'),
(8,10,5,'走访了南通地区3位蓝印花布传承人，收集了大量一手口述资料。王奶奶92岁，是目前年龄最大的传承人，她讲述了40年代蓝印花布的染制细节。完成了调研报告初稿。','/uploads/submissions/sub_008.pdf',0,NULL,NULL,'2025-04-10 14:00:00',NULL,'2025-04-10 14:00:00','2025-04-10 14:00:00'),
(9,2,6,'完成了5组不同浓度的染料配制实验。最大发现是加入少量米醋可以增加色牢度。同时记录了浸泡30分钟到4小时的色彩渐变效果。','/uploads/submissions/sub_009.pdf',0,NULL,NULL,'2025-04-05 14:00:00',NULL,'2025-04-05 14:00:00','2025-04-05 14:00:00'),
(10,4,7,'完成了一幅小型双面绣作品——兰花。正面为盛开的兰花，背面为含苞待放。藏针还不够熟练，有几处可以看到线头。','/uploads/submissions/sub_010.jpg',0,NULL,NULL,'2025-04-15 11:00:00',NULL,'2025-04-15 11:00:00','2025-04-15 11:00:00');
INSERT INTO `learning_material` (`id`,`title`,`description`,`file_url`,`file_type`,`file_size`,`task_id`,`uploader_id`,`heritage_project_id`,`created_at`,`updated_at`) VALUES
(1,'蓝印花布传统图案集','收录了100多种蓝印花布经典图案，包含花卉、动物、人物、几何纹样等分类，每个图案附有尺寸标注。','/uploads/materials/mat_001.pdf','PDF',15728640,1,2,1,'2025-02-10 08:30:00','2025-02-10 08:30:00'),
(2,'刻版工具使用指南','详细介绍了刻版刀、油纸板、浆料等工具的使用方法、保养技巧和常见问题处理。','/uploads/materials/mat_002.pdf','PDF',5242880,1,2,1,'2025-02-10 08:45:00','2025-02-10 08:45:00'),
(3,'天然靛蓝染料配制手册','记录传统靛蓝染料的配制方法、不同浓度色彩效果、温度与时间的控制要领，附实验数据。','/uploads/materials/mat_003.pdf','PDF',8388608,2,2,1,'2025-02-20 10:30:00','2025-02-20 10:30:00'),
(4,'苏绣基础针法教学视频','李师傅亲自示范平绣、齐针、套针、施针四种基础针法的操作要领，含慢动作回放。','/uploads/materials/mat_004.mp4','VIDEO',524288000,3,3,3,'2025-02-15 09:30:00','2025-02-15 09:30:00'),
(5,'苏绣配色指南','介绍苏绣传统配色方案和丝线选择方法，含50组经典配色组合，附色卡对照表。','/uploads/materials/mat_005.pdf','PDF',10485760,3,3,3,'2025-02-15 10:00:00','2025-02-15 10:00:00'),
(6,'双面绣技法详解','详细讲解双面绣核心技法：起针不留痕、转针无接头、藏针无断线，图文并茂。','/uploads/materials/mat_006.pdf','PDF',12582912,4,3,3,'2025-03-01 14:30:00','2025-03-01 14:30:00'),
(7,'景德镇传统拉坯教程','王师傅录制的拉坯全流程教学视频，从揉泥到成型的完整演示，含碗杯瓶三种器型。','/uploads/materials/mat_007.mp4','VIDEO',734003200,5,4,2,'2025-03-01 08:30:00','2025-03-01 08:30:00'),
(8,'青花瓷绘制技法图解','包含分水、勾线、染色三大技法的图文详解，附历代经典青花纹样赏析和临摹范本。','/uploads/materials/mat_008.pdf','PDF',20971520,6,4,2,'2025-03-15 10:30:00','2025-03-15 10:30:00'),
(9,'非遗项目申报指南','整理了国家级、省级非遗项目的申报流程、条件与注意事项，含成功案例分析。','/uploads/materials/mat_009.pdf','PDF',3145728,NULL,2,1,'2025-02-01 09:00:00','2025-02-01 09:00:00'),
(10,'传统手工艺品鉴赏教材','系统介绍了中国十大传统手工艺的发展历程、工艺特点与鉴赏方法。','/uploads/materials/mat_010.pdf','PDF',41943040,NULL,4,2,'2025-01-20 10:00:00','2025-01-20 10:00:00'),
(11,'蓝印花布历史演变图册','从宋代到现代蓝印花布的演变历程，收录珍贵历史照片200余幅。','/uploads/materials/mat_011.pdf','PDF',52428800,NULL,2,1,'2025-02-05 09:00:00','2025-02-05 09:00:00'),
(12,'苏绣丝线材料手册','介绍苏绣常用的各种丝线材料的特性、适用针法及保存方法。','/uploads/materials/mat_012.pdf','PDF',6291456,3,3,3,'2025-02-16 10:00:00','2025-02-16 10:00:00');
INSERT INTO `artwork` (`id`,`title`,`description`,`apprentice_id`,`master_id`,`heritage_project_id`,`skill_category_id`,`image_urls`,`video_url`,`status`,`created_at`,`updated_at`) VALUES
(1,'春归蓝印花布围巾','以春天回归为主题，采用传统蓝印花布工艺制作的围巾。图案以燕子归巢和桃花盛开为主要元素，寓意春回大地。特意选用老棉布为底料。',5,2,1,13,'https://picsum.photos/seed/art01/400/300',NULL,2,'2025-03-15 14:00:00','2025-03-18 10:00:00'),
(2,'蓝印花布茶席套装','运用传统蓝印花布技艺制作的茶席套装，包含茶垫、杯垫和壶承三件套。图案选用莲花与荷叶，体现茶道清雅之韵。',6,2,1,13,'https://picsum.photos/seed/art02/400/300',NULL,2,'2025-03-20 10:00:00','2025-03-22 15:00:00'),
(3,'牡丹蝴蝶苏绣团扇','以传统工笔画风格绣制的牡丹蝴蝶团扇，采用平绣与套针相结合的技法，色彩层次丰富。耗时约120小时完成。',7,3,3,9,'https://picsum.photos/seed/art03/400/300',NULL,2,'2025-03-25 11:00:00','2025-03-28 09:00:00'),
(4,'锦鲤戏水双面绣小品','初次尝试双面绣技法的习作，以锦鲤戏水为主题。正面为全景，背面为局部特写。虽有不足但已初具双面绣神韵。',8,3,3,9,'https://picsum.photos/seed/art04/400/300',NULL,1,'2025-03-30 14:00:00','2025-03-30 14:00:00'),
(5,'青花瓷茶杯组','在王师傅指导下完成的第一组青花瓷茶杯，采用传统缠枝莲纹装饰，釉面温润，花色清雅。一套四杯，个个精心绘制。',9,4,2,10,'https://picsum.photos/seed/art05/400/300',NULL,2,'2025-04-01 10:00:00','2025-04-03 14:00:00'),
(6,'粉彩花鸟小瓶','练习粉彩技法的习作，以喜鹊登梅为题材，釉上彩绘制而成。色彩搭配已初显功力，但渐变过渡需提升。',10,4,2,10,'https://picsum.photos/seed/art06/400/300',NULL,1,'2025-04-05 15:00:00','2025-04-05 15:00:00'),
(7,'蓝印花布手提袋','将传统蓝印花布与现代手提袋设计结合，图案采用传统万字纹和祥云纹，实用与美观兼备。参加了校园文创市集。',5,2,1,13,'https://picsum.photos/seed/art07/400/300',NULL,1,'2025-04-10 09:00:00','2025-04-10 09:00:00'),
(8,'梅花三弄苏绣挂画','以梅花为主题的苏绣挂画，运用了乱针绣技法表现梅花的枝干质感，是一次大胆的技法创新尝试。',7,3,3,9,'https://picsum.photos/seed/art08/400/300',NULL,0,'2025-04-12 16:00:00','2025-04-12 16:00:00'),
(9,'仿古青花瓷盘','参考元代青花瓷经典纹样，在30cm瓷盘上绘制的仿古青花作品。青料发色浓艳，线条遒劲有力。',9,4,2,10,'https://picsum.photos/seed/art09/400/300',NULL,1,'2025-04-15 10:00:00','2025-04-15 10:00:00'),
(10,'蓝印花布抱枕','以鱼戏莲为主题的蓝印花布抱枕，表达年年有余的美好寓意。使用天然棉料填充。',6,2,1,13,'https://picsum.photos/seed/art10/400/300',NULL,0,'2025-04-18 11:00:00','2025-04-18 11:00:00'),
(11,'百蝶穿花苏绣屏风','耗时三个月完成的大型苏绣作品，描绘了百只蝴蝶在花丛中穿梭的场景。运用了十余种针法。',8,3,3,9,'https://picsum.photos/seed/art11/400/300',NULL,2,'2025-04-20 14:00:00','2025-04-25 10:00:00'),
(12,'青花瓷笔筒','采用传统山水题材绘制的青花瓷笔筒，表现了"渔舟唱晚"的意境。',9,4,2,10,'https://picsum.photos/seed/art12/400/300',NULL,2,'2025-04-22 09:00:00','2025-04-26 11:00:00'),
(13,'蓝印花布书衣','用蓝印花布制作的线装书封面，图案选用传统"福禄寿"纹样，将传统印染与装帧艺术结合。',5,2,1,13,'https://picsum.photos/seed/art13/400/300',NULL,2,'2025-04-25 10:00:00','2025-04-28 09:00:00'),
(14,'荷塘清趣苏绣扇面','以荷塘为主题的苏绣扇面，细腻表现了荷花、荷叶、蜻蜓等元素。运用了渐变色套针技法。',7,3,3,9,'https://picsum.photos/seed/art14/400/300',NULL,1,'2025-04-28 15:00:00','2025-04-28 15:00:00'),
(15,'窑变釉花瓶','尝试窑变釉烧制技法的作品，釉面呈现出意想不到的蓝紫渐变效果，被王师傅赞为"窑宝"。',10,4,2,10,'https://picsum.photos/seed/art15/400/300',NULL,2,'2025-05-01 10:00:00','2025-05-05 14:00:00');
INSERT INTO `artwork_review` (`id`,`artwork_id`,`reviewer_id`,`content`,`score`,`created_at`,`updated_at`) VALUES
(1,1,2,'整体构图合理，燕子的形态生动，桃花的色彩渲染自然。在刻版线条的粗细变化上可以更加大胆，让图案更有层次感。作为初期作品已经很不错了！',88,'2025-03-18 10:00:00','2025-03-18 10:00:00'),
(2,2,2,'茶席套装的设计理念很好，莲花荷叶的图案与茶道文化非常契合。蓝白色调的深浅过渡需要更加细腻，建议多研究传统蓝印花布的层次表现技法。',85,'2025-03-22 15:00:00','2025-03-22 15:00:00'),
(3,3,3,'构图饱满，配色雅致，牡丹的花瓣层次感处理得很好。蝴蝶翅膀的渐变色可以再细腻一些，建议用套针技法来增强色彩过渡效果。同期最佳作品。',90,'2025-03-28 09:00:00','2025-03-28 09:00:00'),
(4,5,4,'杯型规整，拉坯功底扎实。缠枝莲纹的绘制线条流畅，分水均匀。建议在口沿和足部的处理上再精细一些，这是判断瓷器品质的关键细节。',86,'2025-04-03 14:00:00','2025-04-03 14:00:00'),
(5,1,2,'追加点评：围巾的整体色牢度测试合格，洗涤后不褪色。建议下次注意浆料涂抹的均匀度，局部有轻微渗色。',88,'2025-03-25 09:00:00','2025-03-25 09:00:00'),
(6,3,3,'再次审阅作品，花瓣的针脚密度非常均匀，这在初学者中非常难得。建议下一步可以尝试更复杂的题材，如山水或人物。',92,'2025-04-01 10:00:00','2025-04-01 10:00:00'),
(7,5,4,'追加点评：经过高温烧制后釉面光滑无瑕疵，说明温度控制得当。建议尝试更大器型的制作。',88,'2025-04-10 09:00:00','2025-04-10 09:00:00'),
(8,11,3,'百蝶穿花的构图大气磅礴，每只蝴蝶形态各异，显示出扎实的造型功底。色彩和谐统一，多种针法的运用炉火纯青。是目前为止最优秀的作品。',95,'2025-04-25 10:00:00','2025-04-25 10:00:00'),
(9,12,4,'笔筒的器型端正，青花发色纯正。山水画面的构图有古韵，远山近水的层次感处理得很好。可以在细节上再精雕细琢。',87,'2025-04-26 11:00:00','2025-04-26 11:00:00'),
(10,13,2,'书衣的创意很好，将蓝印花布与传统装帧结合是一个很有前景的方向。工艺细节到位，建议多尝试不同的纹样搭配。',89,'2025-04-28 09:00:00','2025-04-28 09:00:00'),
(11,15,4,'窑变釉的效果出人意料地好！蓝紫渐变自然流畅，说明对窑温的把控有了很大进步。这件作品值得好好收藏。',93,'2025-05-05 14:00:00','2025-05-05 14:00:00');
