INSERT INTO `activity` (`id`,`title`,`description`,`content`,`cover_url`,`location`,`start_time`,`end_time`,`max_participants`,`current_participants`,`heritage_project_id`,`status`,`publisher_id`,`created_at`,`updated_at`) VALUES
(1,'非遗文化公开讲座：蓝印花布的前世今生','邀请国家级非遗传承人讲述蓝印花布的历史渊源、工艺特色与当代价值。','本次讲座将从以下几个方面展开：\n1. 蓝印花布的历史沿革（明清至今）\n2. 传统印染工艺流程详解\n3. 蓝印花布图案的文化内涵\n4. 传统技艺的现代创新应用\n5. 互动问答与现场体验','https://picsum.photos/seed/act01/800/400','南通非遗展览馆报告厅','2025-03-15 09:00:00','2025-03-15 12:00:00',50,35,1,2,1,'2025-02-28 10:00:00','2025-03-15 12:00:00'),
(2,'苏绣艺术展览：针尖上的诗画','展出苏州刺绣研究所及民间传承人的精品苏绣作品，含现场刺绣演示。','展览内容包括：\n- 历代苏绣精品50余幅\n- 双面绣、乱针绣等技法演示\n- 苏绣与现代时尚的融合作品\n- 现场体验区（免费提供材料）','https://picsum.photos/seed/act02/800/400','苏州丝绸博物馆','2025-04-05 10:00:00','2025-04-10 17:00:00',200,86,3,1,1,'2025-03-20 14:00:00','2025-04-05 10:00:00'),
(3,'景德镇陶瓷文化研学营','为期三天的景德镇陶瓷文化深度研学，体验从制泥到出窑的完整工序。','研学行程：\nDay 1：参观古窑民俗博览区，了解千年制瓷历史\nDay 2：亲手体验拉坯、画坯，在传承人指导下完成作品\nDay 3：参观现代陶瓷工厂，了解传统与现代的结合','https://picsum.photos/seed/act03/800/400','江西景德镇古窑民俗博览区','2025-05-01 08:00:00','2025-05-03 18:00:00',30,12,2,0,1,'2025-04-01 09:00:00','2025-04-01 09:00:00'),
(4,'非遗技艺体验日：走进传统手工艺','面向社会公众的非遗技艺体验活动，设置剪纸、蓝印花布、陶艺等多个体验区。','活动设置以下体验区：\n1. 剪纸体验区\n2. 蓝印花布体验区\n3. 陶艺体验区\n4. 刺绣体验区\n每人可选择2个体验区参与','https://picsum.photos/seed/act04/800/400','市文化活动中心','2025-04-20 09:00:00','2025-04-20 17:00:00',100,45,NULL,0,1,'2025-04-05 10:00:00','2025-04-05 10:00:00'),
(5,'非遗传承人座谈会','邀请多位非遗传承人分享传承经验，探讨非遗保护与数字化发展方向。','座谈主题：\n1. 师徒传承模式的现状与挑战\n2. 数字化技术在非遗保护中的应用\n3. 非遗产品的市场化探索\n4. 年轻一代传承人的培养路径','https://picsum.photos/seed/act05/800/400','文化馆三楼会议室','2025-05-15 14:00:00','2025-05-15 17:00:00',40,0,NULL,0,1,'2025-04-20 09:00:00','2025-04-20 09:00:00'),
(6,'蓝印花布创意设计大赛','面向所有学习蓝印花布技艺的徒弟，以"传统与创新"为主题的创意设计比赛。','比赛规则：\n1. 参赛作品须以传统蓝印花布工艺制作\n2. 鼓励融入现代设计元素\n3. 作品需附创作说明\n4. 由专家评审团评选金银铜奖','https://picsum.photos/seed/act06/800/400','线上提交 + 线下展览','2025-06-01 00:00:00','2025-06-30 23:59:59',50,0,1,0,1,'2025-05-01 10:00:00','2025-05-01 10:00:00'),
(7,'传统木雕工艺观摩学习','组织参观东阳木雕博物馆，近距离观摩国家级木雕大师的创作过程。','行程安排：\n上午：参观东阳木雕博物馆\n下午：观摩大师现场创作\n交流：与木雕传承人面对面交流','https://picsum.photos/seed/act07/800/400','浙江东阳木雕博物馆','2025-07-10 08:00:00','2025-07-10 17:00:00',25,0,4,0,1,'2025-06-01 09:00:00','2025-06-01 09:00:00'),
(8,'非遗进校园系列活动','组织非遗传承人走进中小学校园，向学生展示传统技艺，播撒非遗文化种子。','活动包括：\n1. 传承人技艺展示\n2. 学生互动体验\n3. 非遗文化小课堂\n4. 合影留念','https://picsum.photos/seed/act08/800/400','市第一中学多功能厅','2025-06-15 09:00:00','2025-06-15 16:00:00',150,0,NULL,0,1,'2025-05-15 10:00:00','2025-05-15 10:00:00');
