INSERT INTO `announcement` (`id`,`title`,`content`,`publisher_id`,`is_top`,`status`,`created_at`,`updated_at`) VALUES
(1,'关于非遗技艺师徒档案传承管理系统正式上线的通知','各位师傅、徒弟及相关工作人员：\n\n非遗技艺"师徒档案"传承管理系统已于2025年1月1日正式上线运行。该系统旨在通过数字化手段，规范师徒传承流程，留存学习过程数据，为非遗技艺的保护与传承提供有力支撑。\n\n请各位用户及时完善个人档案，如有使用问题请联系系统管理员。\n\n特此通知。',1,1,1,'2025-01-01 10:00:00','2025-01-01 10:00:00'),
(2,'2025年度非遗传承人培训计划发布','经过前期调研和专家论证，2025年度非遗传承人培训计划现已制定完成。\n\n1. 传统技艺基础培训（3-4月）\n2. 创新设计能力提升培训（5-6月）\n3. 非遗数字化保护技术培训（7-8月）\n4. 市场化运营实践培训（9-10月）\n\n详细课程安排将另行通知。',1,1,1,'2025-01-15 09:00:00','2025-01-15 09:00:00'),
(3,'系统维护通知','为提升系统性能和用户体验，系统将于2025年2月28日晚22:00-次日凌晨2:00进行维护升级。维护期间系统暂停服务。\n\n给您带来的不便，敬请谅解。',1,0,1,'2025-02-25 14:00:00','2025-02-25 14:00:00'),
(4,'关于规范师徒关系管理的通知','各位师傅：\n\n为确保师徒传承质量，现对师徒关系管理做如下规范：\n1. 每位师傅同时在带徒弟数量建议不超过5名\n2. 拜师申请须在7个工作日内审核\n3. 解除师徒关系需说明原因并经管理员确认\n4. 师傅应定期发布教学任务',1,0,1,'2025-03-01 10:00:00','2025-03-01 10:00:00'),
(5,'非遗技艺体验日活动报名开始','2025年"非遗技艺体验日"将于4月20日在市文化活动中心举办。\n\n报名方式：通过本系统"活动课程"模块在线报名\n报名截止：2025年4月15日\n名额有限，先到先得！',1,0,1,'2025-04-05 10:00:00','2025-04-05 10:00:00'),
(6,'关于提交年度非遗传承工作总结的通知','各位师傅：\n\n请于2025年12月31日前提交本年度非遗传承工作总结。\n\n总结请通过系统提交或发送至管理员邮箱。',1,0,0,'2025-04-15 09:00:00','2025-04-15 09:00:00'),
(7,'关于举办首届非遗技艺网络展览的通知','为扩大非遗技艺的传播影响力，系统将举办首届非遗技艺网络展览。\n\n展览时间：2025年7月1日-7月31日\n参展方式：通过系统上传作品\n\n优秀作品将在系统首页推荐展示',1,1,1,'2025-04-20 10:00:00','2025-04-20 10:00:00'),
(8,'师徒传承成果展示月活动启动','为展示非遗传承成果，激励师徒积极参与传承活动，特举办"师徒传承成果展示月"。\n\n活动期间将评选：\n- 最佳师傅奖（3名）\n- 最佳进步徒弟奖（5名）\n- 最佳作品奖（10名）',1,0,1,'2025-05-01 09:00:00','2025-05-01 09:00:00'),
(9,'关于加强非遗知识产权保护的通知','为保护传统技艺知识产权，现通知如下：\n\n1. 所有上传作品均受知识产权保护\n2. 未经作者同意不得擅自使用\n3. 系统已开通版权登记快捷通道\n4. 如发现侵权行为请及时举报',1,0,1,'2025-05-10 10:00:00','2025-05-10 10:00:00'),
(10,'端午节非遗文化特别活动预告','端午节期间将举办"指尖上的端午"非遗文化特别活动，包括：\n- 端午主题剪纸创作\n- 蓝印花布粽子香囊制作\n- 苏绣端午荷包体验\n\n活动详情即将发布！',1,1,1,'2025-05-20 09:00:00','2025-05-20 09:00:00');
